// Parse the Super Agent enhanced extraction response
const agentResponse = $input.first().json.response;
let parsed;
try {
  const jsonMatch = agentResponse.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(jsonMatch ? jsonMatch[0] : agentResponse);
} catch (e) {
  // Fall back to raw Mindee data if Super Agent parsing fails
  const mindeeData = $('Extract Invoice Data').first().json;
  parsed = {
    ...mindeeData,
    extraction_confidence: 0,
    ocr_corrections: [],
    missing_fields: ['super_agent_parse_failed']
  };
}
return [{ json: parsed }];

// Parse the Super Agent categorization response
const agentResponse = $input.first().json.response;
let parsed;
try {
  const jsonMatch = agentResponse.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(jsonMatch ? jsonMatch[0] : agentResponse);
} catch (e) {
  parsed = {
    category: 'Uncategorized',
    subcategory: '',
    vendor: 'Unknown',
    amount: 0,
    date: new Date().toISOString().split('T')[0],
    description: agentResponse,
    anomaly_flag: true,
    anomaly_severity: 'high',
    anomaly_reason: 'Could not parse categorization response',
    anomaly_recommendations: ['Manual review required'],
    confidence_score: 0,
    budget_line: 'Unknown',
    tax_verified: false,
    line_items_verified: false
  };
}

return [{
  json: {
    ...parsed,
    anomaly_recommendations: Array.isArray(parsed.anomaly_recommendations)
      ? parsed.anomaly_recommendations.join('; ')
      : (parsed.anomaly_recommendations || ''),
    processed_date: new Date().toISOString()
  }
}];

